 export fn zell_version_patch() c_int {
     return ZELL_VERSION_PATCH;
 }
+
+// ============================================================================
+// Streaming API (for direct Swift integration)
+// ============================================================================
+
+/// Callback function pointer type for streaming tokens
+pub const TokenCallback = ?*const fn (token: [*:0]const u8, token_len: c_int, user_data: ?*anyopaque) void;
+
+/// Start async generation with streaming callback
+/// Returns: cell_id on success, negative error code on failure
+export fn zell_predict_streaming(
+    prompt: [*:0]const u8,
+    max_tokens: c_int,
+    callback: TokenCallback,
+    user_data: ?*anyopaque,
+) c_int {
+    const scheduler = global_scheduler orelse return -1;
+    const prompt_slice = std.mem.sliceTo(prompt, 0);
+
+    // Find idle cell
+    const cell_id = scheduler.findIdleCell() orelse return -1;
+
+    // Get cell and store callback
+    var cell = &scheduler.cells[cell_id];
+    cell.token_callback = callback;
+    cell.callback_user_data = user_data;
+    cell.bytes_consumed = 0;
+
+    // Submit prompt (no adapter)
+    scheduler.submit(cell_id, prompt_slice, @intCast(@max(1, max_tokens)), null) catch return -1;
+
+    return @intCast(cell_id);
+}
+
+/// Cancel generation for a cell
+export fn zell_cancel(cell_id: c_int) void {
+    const scheduler = global_scheduler orelse return;
+    const id: u32 = @intCast(cell_id);
+    if (id >= scheduler.cells.len) return;
+
+    var cell = &scheduler.cells[id];
+    cell.state = .completed;
+    cell.reset();
+}
+
+// ============================================================================
+// Background runner thread (runs scheduler.step() continuously)
+// ============================================================================
+
+var runner_thread: ?std.Thread = null;
+var runner_should_stop: std.atomic.Value(bool) = std.atomic.Value(bool).init(false);
+
+fn schedulerRunLoop() void {
+    while (!runner_should_stop.load(.acquire)) {
+        if (global_scheduler) |sched| {
+            _ = sched.step() catch {};
+        }
+        std.Thread.sleep(5_000_000); // 5ms
+    }
+}
+
+/// Start background scheduler thread
+export fn zell_start_runner() void {
+    if (runner_thread != null) return; // Already running
+
+    runner_should_stop.store(false, .release);
+    runner_thread = std.Thread.spawn(.{}, schedulerRunLoop, .{}) catch {
+        std.debug.print("Failed to start runner thread\n", .{});
+        return;
+    };
+}
+
+/// Stop background scheduler thread
+export fn zell_stop_runner() void {
+    if (runner_thread == null) return;
+
+    runner_should_stop.store(true, .release);
+    if (runner_thread) |thread| {
+        thread.join();
+    }
+    runner_thread = null;
+}

